import {useRef,useState} from 'react';export default function AddToPlaylist(){const[s,setS]=useState('');const[list,setL]=useState([]);const ref=useRef();const add=e=>{e.preventDefault();if(!s){alert('Enter song');ref.current.focus();return;}setL([...list,s]);setS('');ref.current.focus();};return <div className='card p-3'><form onSubmit={add}><h4>Add Playlist</h4><input ref={ref} value={s} onChange={e=>setS(e.target.value)} className='form-control'/><button className='btn btn-primary mt-2'>Add</button></form><ul className='list-group mt-2'>{list.map((i,k)=><li key={k} className='list-group-item'>{i}</li>)}</ul></div>}